/*
   Global design system inspired by the provided hero layout
   - Clean, modern, conversion-focused
   - White header over dark imagery, bright blue accents
*/

:root {
    /* Brand palette */
    --color-primary-500: #008CDA; /* main CTA / links */
    --color-primary-600: #0066B3; /* hover / emphasis */
    --color-primary-400: #00A0E6;
    --color-primary-300: #00AEEF;

    --color-secondary-100: #E6F2FF; /* light backgrounds */

    --color-neutral-000: #FFFFFF;
    --color-neutral-050: #F5F7FB;
    --color-neutral-200: #E5E7EB;
    --color-neutral-800: #1F2933;

    --color-success: #16A34A;
    --color-error: #DC2626;
    --color-warning: #F59E0B;
    --color-info: #0284C7;

    /* Typography */
    --font-heading: 'Space Grotesk', Helvetica, sans-serif;
    --font-body: 'IBM Plex Sans', Arial, sans-serif;
    --font-code: 'Source Code Pro', monospace;

    --text-color-main: #0F172A;
    --text-color-muted: #6B7280;
    --text-on-dark: #F9FAFB;

    --font-size-h1: 3rem;   /* 48px */
    --font-size-h2: 2rem;   /* 32px */
    --font-size-h3: 1.375rem; /* 22px */
    --font-size-body: 0.9375rem; /* 15px */
    --font-size-small: 0.8125rem; /* 13px */

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing scale (4px base multiplier) */
    --space-0-5: 0.125rem;  /* 2px */
    --space-1: 0.25rem;     /* 4px */
    --space-2: 0.5rem;      /* 8px */
    --space-3: 1rem;        /* 16px */
    --space-4: 1.5rem;      /* 24px */
    --space-5: 2rem;        /* 32px */
    --space-6: 3rem;        /* 48px */
    --space-7: 4rem;        /* 64px */

    /* Layout */
    --site-max-width: 1200px;
    --header-height: 4.5rem; /* 72px, matches airy header */

    /* Effects */
    --shadow-soft: 0 10px 30px rgba(15, 23, 42, 0.08);
    --radius-sm: 0.25rem;   /* 4px */
    --radius-md: 0.375rem;  /* 6px */
    --radius-lg: 1.5rem;    /* 24px */
}

/* Global reset / base ----------------------------------------------------- */

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body.site {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--text-color-main);
    background-color: var(--color-neutral-050);
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: none;
}

.container {
    max-width: var(--site-max-width);
    margin: 0 auto;
    padding-inline: var(--space-4);
}

.site-content {
    min-height: calc(100vh - var(--header-height) - 220px);
}

/* Header ------------------------------------------------------------------ */

.site-header {
    position: sticky;
    top: 0;
    z-index: 40;
    height: var(--header-height);
    background-color: var(--color-neutral-000);
    box-shadow: 0 1px 0 rgba(148, 163, 184, 0.25);
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 100%;
    gap: var(--space-4);
}

/* Logo area mimicking the compact logo in the design */

.logo {
    display: inline-flex;
    align-items: center;
    gap: var(--space-2);
    text-decoration: none;
}

.logo-mark {
    width: 44px;
    height: 44px;
    border-radius: var(--radius-sm);
    background: linear-gradient(135deg, var(--color-primary-500), var(--color-primary-300));
    box-shadow: 0 4px 12px rgba(0, 140, 218, 0.35);
}

.logo-text {
    display: flex;
    flex-direction: column;
    line-height: 1.1;
}

.logo-title {
    font-family: var(--font-heading);
    font-weight: 700;
    font-size: 1.05rem;
    color: #111827;
}

.logo-subtitle {
    font-size: 0.75rem;
    color: var(--text-color-muted);
}

/* Primary navigation ------------------------------------------------------ */

.primary-nav {
    display: flex;
}

.nav-list {
    display: flex;
    align-items: center;
    gap: var(--space-4);
    list-style: none;
    margin: 0;
    padding: 0;
}

.nav-item {
    display: flex;
}

.nav-link {
    font-family: var(--font-body);
    font-size: 0.9375rem;
    font-weight: 500;
    color: var(--color-primary-500);
    padding-block: 0.375rem;
    position: relative;
    transition: color 0.15s ease;
}

.nav-link::after {
    content: '';
    position: absolute;
    left: 0;
    right: 0;
    bottom: -0.3rem;
    height: 2px;
    border-radius: 999px;
    background-color: var(--color-primary-500);
    opacity: 0;
    transform: scaleX(0.75);
    transition: opacity 0.15s ease, transform 0.15s ease;
}

.nav-link:hover,
.nav-link:focus {
    color: var(--color-primary-600);
}

.nav-link:hover::after,
.nav-link:focus::after {
    opacity: 1;
    transform: scaleX(1);
}

/* CTA-style nav item, mirroring outline button in design */

.nav-item-cta {
    margin-left: var(--space-3);
}

.nav-link-cta {
    padding-inline: 1.25rem;
    padding-block: 0.55rem;
    border-radius: var(--radius-md);
    border: 1px solid var(--color-primary-500);
    background-color: var(--color-neutral-000);
    color: var(--color-primary-500);
    font-weight: 600;
    box-shadow: none;
}

.nav-link-cta::after {
    display: none;
}

.nav-link-cta:hover,
.nav-link-cta:focus {
    background-color: var(--secondary-100, #E6F2FF);
    color: var(--color-primary-600);
    border-color: var(--color-primary-600);
}

/* Footer ------------------------------------------------------------------ */

.site-footer {
    margin-top: var(--space-6);
    background: radial-gradient(circle at top left, #0B2239 0%, #041421 55%, #020816 100%);
    color: var(--text-on-dark);
    padding-top: var(--space-6);
}

.footer-inner {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    gap: var(--space-5);
    padding-bottom: var(--space-5);
}

.footer-brand {
    display: flex;
    align-items: flex-start;
    gap: var(--space-3);
    max-width: 320px;
}

.footer-logo-mark {
    width: 40px;
    height: 40px;
    border-radius: 0.35rem;
    background: linear-gradient(135deg, var(--color-primary-500), var(--color-primary-300));
    box-shadow: 0 6px 18px rgba(0, 140, 218, 0.45);
}

.footer-text {
    display: flex;
    flex-direction: column;
    gap: var(--space-1);
}

.footer-title {
    font-family: var(--font-heading);
    font-weight: 600;
    font-size: 1rem;
}

.footer-subtitle {
    font-size: var(--font-size-small);
    color: rgba(226, 232, 240, 0.85);
}

.footer-links-grid {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-5);
}

.footer-links-group {
    min-width: 160px;
}

.footer-heading {
    font-family: var(--font-heading);
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: rgba(148, 163, 184, 0.95);
    margin: 0 0 var(--space-2) 0;
}

.footer-links {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    flex-direction: column;
    gap: 0.45rem;
}

.footer-links a {
    font-size: 0.9rem;
    color: rgba(226, 232, 240, 0.9);
    transition: color 0.15s ease;
}

.footer-links a:hover,
.footer-links a:focus {
    color: var(--color-primary-300);
}

.footer-bottom {
    border-top: 1px solid rgba(30, 64, 175, 0.5);
    padding-block: var(--space-3);
}

.footer-bottom-inner {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: var(--space-3);
}

.footer-copy {
    margin: 0;
    font-size: 0.8rem;
    color: rgba(148, 163, 184, 0.95);
}

/* Utility classes (for future page content) -------------------------------- */

.btn-primary {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding-inline: 1.5rem;
    padding-block: 0.75rem;
    border-radius: var(--radius-md);
    border: none;
    background: linear-gradient(90deg, var(--color-primary-500), var(--color-primary-400));
    color: var(--color-neutral-000);
    font-family: var(--font-body);
    font-size: 0.9375rem;
    font-weight: 600;
    cursor: pointer;
    box-shadow: var(--shadow-soft);
}

.btn-primary:hover,
.btn-primary:focus {
    background: linear-gradient(90deg, var(--color-primary-600), var(--color-primary-500));
}

/* Basic responsive tweaks ------------------------------------------------- */

@media (max-width: 960px) {
    .header-inner {
        gap: var(--space-3);
    }

    .nav-list {
        gap: var(--space-3);
    }

    .nav-item-cta {
        margin-left: var(--space-2);
    }
}

@media (max-width: 768px) {
    .header-inner {
        flex-wrap: wrap;
        justify-content: center;
        padding-block: var(--space-2);
        height: auto;
    }

    .site-header {
        height: auto;
    }

    .primary-nav {
        width: 100%;
        justify-content: center;
    }

    .nav-list {
        flex-wrap: wrap;
        justify-content: center;
        row-gap: var(--space-2);
        column-gap: var(--space-3);
    }

    .nav-item-cta {
        margin-left: 0;
    }

    .footer-inner {
        flex-direction: column;
        align-items: flex-start;
    }

    .footer-bottom-inner {
        flex-direction: column;
        align-items: flex-start;
    }
}
